<?php
$pdo_host = getenv('PDO_HOST') ?: 'localhost';
$pdo_dbname = getenv('PDO_DBNAME') ?: 'database_name';
$pdo_user = getenv('PDO_USER') ?: 'database_user';
$pdo_pass = getenv('PDO_PASS') ?: 'database_password';
$pdo_charset = 'utf8mb4';
$pdo_dsn = "mysql:host={$pdo_host};dbname={$pdo_dbname};charset={$pdo_charset}";
try {
    $pdo = new PDO($pdo_dsn, $pdo_user, $pdo_pass, [
        PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
        PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
        PDO::ATTR_EMULATE_PREPARES => false,
    ]);
} catch (PDOException $e) {
    http_response_code(500);
    die('Database connection failed: ' . $e->getMessage());
}
?>
